// Parse part numbers from form input
const formData = $input.first().json;
const partsText = (formData.part_numbers || '').trim();
const leadTimeThreshold = parseInt(formData.lead_time_threshold || '12', 10);
const notes = (formData.notes || '').trim();

function normalizePartLine(line) {
  const clean = line.replace(/^\s*[-*•]\s*/, '').trim();
  if (clean.includes('—')) {
    const [part, ...rest] = clean.split('—');
    return { part_number: part.trim(), manufacturer: rest.join('—').trim() };
  }
  if (clean.includes(' - ')) {
    const [part, ...rest] = clean.split(' - ');
    return { part_number: part.trim(), manufacturer: rest.join(' - ').trim() };
  }
  return { part_number: clean, manufacturer: '' };
}

const lines = partsText.split(/\r?\n/).map(s => s.trim()).filter(Boolean);

const parts = lines.map((line, index) => {
  const { part_number, manufacturer } = normalizePartLine(line);
  return {
    id: `part-${index + 1}`,
    part_number,
    manufacturer,
    lead_time_threshold: leadTimeThreshold,
    notes
  };
});

return parts.map(p => ({ json: p }));

// Build a numbered part list for LLM planning
const items = $input.all();
let partList = '';
let leadTimeThreshold = 12;
let notes = '';

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  if (i === 0) {
    leadTimeThreshold = item.lead_time_threshold || 12;
    notes = item.notes || '';
  }
  if (item.manufacturer) {
    partList += `${i + 1}. ${item.part_number} (${item.manufacturer})`;
  } else {
    partList += `${i + 1}. ${item.part_number}`;
  }
  if (i < items.length - 1) partList += '\n';
}

return { json: { partList, leadTimeThreshold, notes } };

// Parse the OpenAI JSON response and extract scan goals
const j = $input.first().json;

const text =
  j?.output?.[0]?.content?.find(c => c?.type === 'output_text')?.text
  ?? j?.output?.[0]?.content?.[0]?.text
  ?? null;

if (!text || typeof text !== 'string') {
  return [{ json: { error: 'No output_text found in OpenAI response', sample: j } }];
}

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  const stripped = text.replace(/```json\s*|```/g, '').trim();
  parsed = JSON.parse(stripped);
}

const goals = Array.isArray(parsed?.goals) ? parsed.goals : [];

return goals.map(g => ({
  json: {
    part_number: g.part_number || '',
    manufacturer: g.manufacturer || '',
    scan_url: g.scan_url || '',
    goal: g.goal || ''
  }
}));

// Prepare TinyFish run parameters for each part scan
const item = $input.item.json;

let runUrl = item.scan_url || '';
if (!runUrl) {
  const encodedPart = encodeURIComponent(item.part_number);
  runUrl = `https://www.digikey.com/en/products/result?keywords=${encodedPart}`;
}

if (runUrl && !runUrl.startsWith('http://') && !runUrl.startsWith('https://')) {
  runUrl = 'https://' + runUrl;
}

let runGoal = item.goal || '';
if (!runGoal) {
  runGoal = `Search for part number ${item.part_number}${item.manufacturer ? ' by ' + item.manufacturer : ''} on DigiKey. Extract: lifecycle status (Active/NRND/Obsolete), lead time in weeks, stock quantity, unit price at 1000 units, and MOQ. Note any NRND or EOL notices. List exact source URLs for each data point.`;
}

runGoal += '\n\nReturn findings in a structured format with clear labels for: lifecycle_status, lead_time_weeks, stock_quantity, unit_price_1ku, moq, nrnd_notice (true/false), eol_notice (true/false), sources (list of URLs).';

return {
  json: {
    id: item.id,
    part_number: item.part_number,
    manufacturer: item.manufacturer,
    lead_time_threshold: item.lead_time_threshold,
    notes: item.notes,
    runUrl,
    runGoal
  }
};

// Evaluate Runs — aggregate across ALL incoming items
const items = $input.all().map(i => i.json);

let runs = [];
for (const x of items) {
  if (Array.isArray(x)) {
    runs.push(...x);
  } else if (Array.isArray(x?.data)) {
    runs.push(...x.data);
  } else if (Array.isArray(x?.runs)) {
    runs.push(...x.runs);
  } else if (x && (x.run_id || x.status)) {
    runs.push(x);
  }
}

const seen = new Set();
runs = runs.filter(r => {
  const id = r?.run_id ?? r?.runId ?? JSON.stringify(r);
  if (seen.has(id)) return false;
  seen.add(id);
  return true;
});

const terminal = new Set(['COMPLETED', 'FAILED', 'CANCELLED']);
const allDone =
  runs.length > 0 &&
  runs.every(r => terminal.has(String(r.status || '').toUpperCase()));

return [{ json: { raw: items, runs, allDone } }];

// Rehydrate per-run items from aggregated payload
const inItem = $input.first().json;

const arr = Array.isArray(inItem.runs)
  ? inItem.runs
  : (Array.isArray(inItem.raw) ? inItem.raw : []);

const runIds = arr.map(r => r?.run_id || r?.runId).filter(Boolean);

return runIds.map(runId => ({
  json: { runId, run_id: runId }
}));

// Normalize TinyFish runs and merge with part context
const compItems = $("Match Parts with Goals")?.all?.() ?? [];
const parts = compItems.map(it => {
  const j = it.json ?? {};
  return {
    id: j.id ?? null,
    part_number: j.part_number ?? '',
    manufacturer: j.manufacturer ?? '',
    lead_time_threshold: j.lead_time_threshold ?? 12,
    notes: j.notes ?? '',
    runUrl: j.runUrl ?? '',
    runGoal: j.runGoal ?? j.goal ?? ''
  };
}).filter(p => p.part_number);

const inItems = $input.all().map(i => i.json);
let runsRaw = [];
for (const x of inItems) {
  if (Array.isArray(x)) runsRaw.push(...x);
  else if (Array.isArray(x?.data)) runsRaw.push(...x.data);
  else if (Array.isArray(x?.runs)) runsRaw.push(...x.runs);
  else if (x?.run_id || x?.status) runsRaw.push(x);
}

const runs = runsRaw.map(run => {
  const status = String(run.status ?? '').toUpperCase();
  const resultObj = run.result ?? null;
  return {
    run_id: run.run_id ?? null,
    status,
    goal: run.goal ?? '',
    created_at: run.created_at ?? null,
    finished_at: run.finished_at ?? null,
    error: run.error ?? null,
    result: resultObj,
    rawResultText: resultObj ? JSON.stringify(resultObj, null, 2) : ''
  };
});

return [{
  json: {
    parts,
    runs,
    allDone: runs.length > 0 && runs.every(r => ['COMPLETED', 'FAILED', 'CANCELLED'].includes(r.status))
  }
}];

// Build full research payload for LLM risk assessment
const root = $input.first().json;
const parts = Array.isArray(root.parts) ? root.parts : [];
const runs = Array.isArray(root.runs) ? root.runs : [];

const payload = {
  allDone: root.allDone ?? null,
  partCount: parts.length,
  runCount: runs.length,
  parts,
  runs
};

return [{
  json: {
    parts,
    runs,
    allDone: payload.allDone,
    partCount: payload.partCount,
    runCount: payload.runCount,
    researchPayloadText: JSON.stringify(payload, null, 2)
  }
}];

