// Extract and parse the structured risk assessment from OpenAI output
const j = $input.first().json;

const text =
  j?.output?.[0]?.content?.find(c => c?.type === 'output_text')?.text
  ?? j?.output?.[0]?.content?.[0]?.text
  ?? null;

if (!text) {
  return [{ json: { error: 'No output_text in risk assessment response', raw: j } }];
}

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  const stripped = text.replace(/```json\s*|```/g, '').trim();
  try {
    parsed = JSON.parse(stripped);
  } catch (e2) {
    return [{ json: { error: 'Failed to parse JSON', rawText: text } }];
  }
}

return [{ json: { riskAssessment: parsed, rawText: text } }];

// Combine run metadata with risk report
const items = $input.all().map(i => i.json);

const runData = items.find(x => Array.isArray(x.runs) || Array.isArray(x.parts)) || {};
const reportData = items.find(x => x.riskAssessment) || {};

const assessment = reportData.riskAssessment || {};
const parts = Array.isArray(runData.parts) ? runData.parts : [];

return [{
  json: {
    ...runData,
    riskAssessment: assessment,
    generatedAt: new Date().toISOString()
  }
}];

// Build Markdown report content
const j = $json;

const parts = j.parts_scanned || '';
const summary = j.executive_summary || '';
const highRisk = j.high_risk_parts || 'None';
const createdAt = j.scanned_at || new Date().toISOString();

let actionItems = [];
try { actionItems = JSON.parse(j.action_items || '[]'); } catch (e) {}

let fullReport = {};
try { fullReport = JSON.parse(j.full_report_json || '{}'); } catch (e) {}

const partRows = Array.isArray(fullReport.parts)
  ? fullReport.parts.map(p => {
      const risk = p.logistics_risk_level || 'UNKNOWN';
      const emoji = risk === 'CRITICAL' ? '' : risk === 'HIGH' ? '' : risk === 'MEDIUM' ? '' : '';
      return `### ${emoji} ${p.part_number}${p.manufacturer ? ` (${p.manufacturer})` : ''}
- **Lifecycle**: ${p.lifecycle_status || 'Unknown'}
- **Lead Time**: ${p.lead_time_weeks != null ? p.lead_time_weeks + ' weeks' : '—'}
- **Stock**: ${p.stock_quantity != null ? p.stock_quantity.toLocaleString() : '—'}
- **Price (1ku)**: ${p.unit_price_1ku != null ? '$' + p.unit_price_1ku.toFixed(2) : '—'}
- **MOQ**: ${p.moq != null ? p.moq : '—'}
- **NRND Notice**: ${p.nrnd_notice ? ' Yes' : 'No'}
- **EOL Notice**: ${p.eol_notice ? ' Yes' : 'No'}
- **Risk Score**: ${p.logistics_risk_score || '—'} / 100 — **${risk}**
- **Reasoning**: ${p.risk_reasoning || '—'}
- **Sources**: ${Array.isArray(p.sources) ? p.sources.map(s => `[${s}](${s})`).join(', ') : '—'}`;
    }).join('\n\n')
  : '';

const actionMd = actionItems.length
  ? actionItems.map((a, i) => `${i + 1}. ${a}`).join('\n')
  : '_No immediate actions required._';

const safe = (parts || 'scan').replace(/[^a-z0-9-_ ,]/gi, '').slice(0, 60).trim().replace(/[\s,]+/g, '-');
const mdFilename = `siliconsignal-report-${safe}-${Date.now()}.md`;

const mdContent =
`# SiliconSignal — Supply Chain Risk Report

**Parts Scanned:** ${parts}
**Generated:** ${createdAt}

---

## Executive Summary

${summary}

---

##  High / Critical Risk Parts

${highRisk || 'None identified.'}

---

## Per-Part Risk Assessment

${partRows || '_No part data available._'}

---

##  Action Items

${actionMd}
`;

return [{ json: { mdFilename, mdContent } }];

const baseName = ($json.mdFilename || `siliconsignal-report-${Date.now()}`).trim();
const filename = baseName.toLowerCase().endsWith('.md') ? baseName : `${baseName}.md`;
const md = $json.mdContent || '';

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(md, 'utf8'),
  filename,
  'text/markdown'
);

return [{ json: { mdFilename: filename }, binary: { data: binaryData } }];

const data = $json;
const content = JSON.stringify(data, null, 2);
const filename = `siliconsignal-scan-${Date.now()}.json`;

return [{
  json: data,
  binary: {
    data: await this.helpers.prepareBinaryData(
      Buffer.from(content, 'utf8'),
      filename,
      'application/json'
    )
  }
}];
